/**
 * Build the embeddings index for an already-parsed graph.
 *
 * The CLI `parse` command only writes graph.json — embeddings are normally
 * generated by the VS Code extension on first use. CI needs a headless way
 * to produce embeddings.json so the eval runner can load it.
 *
 *   npx tsx eval/build-index.ts [--repo <path>]
 */

import path from "path";
import {
  loadGraph,
  getGraphStorePath,
  getEmbeddingsStorePath,
} from "../src/graph/persistence.js";
import {
  EmbeddingService,
  generateEmbeddings,
} from "../src/graphrag/embeddings.js";
import { VectorStore } from "../src/graphrag/vector-store.js";

async function main() {
  let repo = process.cwd();
  for (let i = 0; i < process.argv.length; i++) {
    if (process.argv[i] === "--repo") repo = process.argv[++i];
  }

  const graphFile = getGraphStorePath(repo);
  const graph = await loadGraph(graphFile);
  if (!graph) {
    console.error(`No graph at ${graphFile}. Run 'npm run parse -- ${repo}' first.`);
    process.exit(1);
  }
  console.log(`Loaded ${graph.order} nodes, ${graph.size} edges from ${graphFile}`);

  const modelCacheDir = path.join(repo, ".graphrepo", "model-cache");
  const embeddingService = new EmbeddingService(modelCacheDir, (msg) => console.log(msg));
  const init = await embeddingService.initialize();
  if (!init.ok) {
    console.error(`Embedding model failed to load: ${init.error}`);
    process.exit(1);
  }

  const vectorStore = new VectorStore();
  const total = await generateEmbeddings(
    graph,
    embeddingService,
    vectorStore,
    (current, totalCount) => {
      process.stdout.write(`\r  Embedding ${current}/${totalCount}`);
    },
  );
  console.log(`\nEmbedded ${total} nodes`);

  const embeddingsFile = getEmbeddingsStorePath(repo);
  vectorStore.save(embeddingsFile);
  console.log(`Saved to ${embeddingsFile}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
